def perceive(data):
    rec = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            rec[k.strip().lower()] = v.strip()
    if not rec:
        return {}

    def num(x):
        x = str(x)
        return int(x) if x.lstrip('-').isdigit() else 0

    cand = {
        "id": rec.get("id", "c?"),
        "blood_type": rec.get("blood", rec.get("blood_type", "O")).upper(),
        "urgency": num(rec.get("urgency", 0)),
        "waiting_days": num(rec.get("days", rec.get("waiting_days", 0))),
        "organ_needed": rec.get("organ", rec.get("organ_needed", "kidney")).lower(),
    }
    return {"incoming": cand}
